WITH payload AS (
  SELECT $RISQQ51${"questions":[{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.15","internal_question_no":"05A.015","question_sort_key":5101500.101,"question_text":"Are the engineering officers familiar with the company procedures for operating the oil filtering equipment, and was the equipment in satisfactory condition and used in compliance with company procedures, the manufacturer’s instructions, and MARPOL Annex I?","guide_to_inspection":"Oil filtering equipment installed on a ship on or after 1 January 2005 must be approved to meet Resolution MEPC.107(49) to\ncomply with MARPOL Annex I Regulation 14.\nThe requirements include;\n> a truly representative sample of the effluent with adequate pressure and flow is supplied to the 15ppm bilge alarm\n(6.2.2).\n> provision of fail-safe arrangements to avoid any discharge in case of malfunction of the 15ppm bilge alarm (4.1.3).\n> 15ppm bilge alarm is fitted with an electronic device that is pre-set to activate when the effluent exceeds 15ppm and\noperates automatically if at any time the 15ppm bilge alarm should fail to function (4.2.7).\n> the response time of the 15ppm bilge alarm. This is the time that elapses between an alteration in the sample being\nsupplied to the 15ppm bilge alarm and the ppm display showing the correct response. Response time should not\nexceed 5 seconds (4.2.6).\n> the setup of the installation must minimise the time it takes for the system to respond when the discharge from the\n15ppm bilge separator exceeds 15ppm. This includes the time it takes for the automatic stopping device to activate\nand prevent discharge into the water. This should take less than 20 seconds. It must not exceed that limit under any\ncircumstances (as per section 6.2.1).\nThe inspector should inspect the condition, and operation, of the oily water separator, filtering equipment and alarm and\nstopping or monitoring arrangements.\nOperational testing of oil filtering equipment will require the equipment to be configured to circulate liquid from bilge tank\nto bilge tank (recirculating facility) and provide an effluent sample to the 15ppm bilge alarm – simulating the discharge of\n15ppm bilge separator effluent overboard. When a simulation of effluent sample greater than 15ppm is applied, the inspector\nshall confirm that the alarm is activated, and that the automatic stopping device (3-way valve) stops effluent discharge\noverboard. This indicates compliant operation of the system.\nThe inspector should confirm that there is a flow of effluent sample from the 15ppm bilge separator that is truly\nrepresentative, with adequate pressure and flow, to the 15ppm bilge alarm while effluent is being simulated to flow\noverboard. In cases where the flow of effluent sample is not a representative sample, including blockage of the sample line or\nincorrect operation of valves, it is expected that, in accordance with MEPC.107(49) requirements, the fail-safe arrangement\nwill activate the automatic stopping device (3-way valve) and stop effluent discharge overboard.\nRightShip’s view aligns with AMSA’s interpretation that the failure of the 15ppm bilge alarm to activate the automatic\nstopping device, in the absence of a representative sample of the effluent, constitutes noncompliance with Resolution\nMEPC.107(49). This indicates that there is no fail-safe arrangement as required by technical specification 4.1.3.\nMEPC 107(49) does not specifically require the fitting of flow or pressure sensors. However, classification societies advocate\nfor the installation of “flow sensors” in the 15ppm bilge alarm sample line. The flow or pressure sensors activate an alarm\nand operate the automatic stopping arrangements when a truly representative sample, with adequate pressure and flow, is\nnot present at the 15ppm bilge alarm. They also recommend the sealing of all valves installed in the effluent sample pipes so\nthat the valves are locked and sealed in their normal operating position to ensure adequate effluent sampling.\nIf a manual valve on the sampling line of the MEPC.107(49)-approved oily water separator is fitted and is not sealed in the\nopen position by Class, the inspector should record a finding.\nIf the manual valve located on the sampling line of the MEPC.107(49)-approved oily water separator is not sealed by Class,\nthe inspector should witness the operational testing of the equipment by shutting the sampling valve and stopping the\nsample water flow to the 15ppm bilge alarm. If the 15ppm bilge alarm does not activate when the effluent sample flow\nis stopped for more than five seconds, and the automatic stopping device is not triggered within twenty seconds, this is\nconsidered a failure of the oily discharge monitoring and control system and the 15ppm alarm arrangements. The inspector\nshould record a finding.\nInspectors shall, when agreed by the Chief Engineer and in full compliance with MARPOL and local environmental\nrequirements, conduct the following operational tests of the oily water separator:\n1. The equipment should be configured to circulate liquid from bilge tank to bilge tank (recirculating facility) and provide an\neffluent sample to the 15ppm bilge alarm, simulating the discharge of 15ppm bilge separator effluent overboard. When a\nsimulation of an effluent sample greater than 15ppm is applied, the inspector shall witness that the alarm is activated, and\nthat the automatic stopping device (3-way valve) stops effluent discharge overboard.\n2. If a sampling valve is provided and is not sealed by Class, the inspector shall request the accompanying engineer officer\nto close the sample valve, thereby interrupting the effluent flow to the 15ppm bilge alarm. The 15ppm bilge alarm must\nactivate within 5 seconds of the effluent sample flow being stopped, and the automatic stopping device must activate within\n20 seconds. If not, this is considered a failure of the oily discharge monitoring and control system and the 15ppm alarm\narrangements.\nInspectors should document any evidence of operational failure of system or failure to respond to an interruption of the\neffluent sample. In the latter instance, the inspector must clearly state the time at which the system responded to the\ninterruption of the effluent sample, triggering the 15ppm bilge alarm, and the time taken for the automatic stopping device to\nactivate.\nAccording to the MEPC 107(49) Chapter 6.1.1, Installation Requirements, it states that “For future inspection purposes on\nboard ship, a sampling point should be provided in a vertical section of the water effluent piping as close as is practicable to\nthe 15ppm bilge separator outlet.”\nThe requirement to install the sampling point in a vertical section of the effluent pipe is to ensure that the sample is\nrepresentative and homogeneous. If the sampling point is installed in a horizontal section of the effluent pipe, there is a risk\nthat the oil is floating at the top and will not be part of the sample.\nAlthough it may be demonstrated that sampling from a horizontal section of the water effluent piping can also result in a\nrepresentative sample, it doesn’t comply with the explicit requirement in MEPC.107(49) to have a sampling point in a vertical\nsection.\nSpecific warning signs should be posted at the overboard discharge valve of the Oily Water Separator. Effective\nsealing arrangements must be in place to prevent accidental opening, and the system should be engineered to\nprovide protection against unauthorized access or unintentional operation of the valves.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":76,"source_page_end":77,"raw_source_text":"Are the engineering officers familiar with the company procedures for operating the oil filtering equipment,\nand was the equipment in satisfactory condition and used in compliance with company procedures, the\nmanufacturer’s instructions, and MARPOL Annex I? (V)\nGuide to Inspection\nOil filtering equipment installed on a ship on or after 1 January 2005 must be approved to meet Resolution MEPC.107(49) to\ncomply with MARPOL Annex I Regulation 14.\nThe requirements include;\n> a truly representative sample of the effluent with adequate pressure and flow is supplied to the 15ppm bilge alarm\n(6.2.2).\n> provision of fail-safe arrangements to avoid any discharge in case of malfunction of the 15ppm bilge alarm (4.1.3).\n> 15ppm bilge alarm is fitted with an electronic device that is pre-set to activate when the effluent exceeds 15ppm and\noperates automatically if at any time the 15ppm bilge alarm should fail to function (4.2.7).\n> the response time of the 15ppm bilge alarm. This is the time that elapses between an alteration in the sample being\nsupplied to the 15ppm bilge alarm and the ppm display showing the correct response. Response time should not\nexceed 5 seconds (4.2.6).\n> the setup of the installation must minimise the time it takes for the system to respond when the discharge from the\n15ppm bilge separator exceeds 15ppm. This includes the time it takes for the automatic stopping device to activate\nand prevent discharge into the water. This should take less than 20 seconds. It must not exceed that limit under any\ncircumstances (as per section 6.2.1).\nThe inspector should inspect the condition, and operation, of the oily water separator, filtering equipment and alarm and\nstopping or monitoring arrangements.\nOperational testing of oil filtering equipment will require the equipment to be configured to circulate liquid from bilge tank\nto bilge tank (recirculating facility) and provide an effluent sample to the 15ppm bilge alarm – simulating the discharge of\n15ppm bilge separator effluent overboard. When a simulation of effluent sample greater than 15ppm is applied, the inspector\nshall confirm that the alarm is activated, and that the automatic stopping device (3-way valve) stops effluent discharge\noverboard. This indicates compliant operation of the system.\nThe inspector should confirm that there is a flow of effluent sample from the 15ppm bilge separator that is truly\nrepresentative, with adequate pressure and flow, to the 15ppm bilge alarm while effluent is being simulated to flow\noverboard. In cases where the flow of effluent sample is not a representative sample, including blockage of the sample line or\nincorrect operation of valves, it is expected that, in accordance with MEPC.107(49) requirements, the fail-safe arrangement\nwill activate the automatic stopping device (3-way valve) and stop effluent discharge overboard.\nRightShip’s view aligns with AMSA’s interpretation that the failure of the 15ppm bilge alarm to activate the automatic\nstopping device, in the absence of a representative sample of the effluent, constitutes noncompliance with Resolution\nMEPC.107(49). This indicates that there is no fail-safe arrangement as required by technical specification 4.1.3.\nMEPC 107(49) does not specifically require the fitting of flow or pressure sensors. However, classification societies advocate\nfor the installation of “flow sensors” in the 15ppm bilge alarm sample line. The flow or pressure sensors activate an alarm\nand operate the automatic stopping arrangements when a truly representative sample, with adequate pressure and flow, is\nnot present at the 15ppm bilge alarm. They also recommend the sealing of all valves installed in the effluent sample pipes so\nthat the valves are locked and sealed in their normal operating position to ensure adequate effluent sampling.\nIf a manual valve on the sampling line of the MEPC.107(49)-approved oily water separator is fitted and is not sealed in the\nopen position by Class, the inspector should record a finding.\nIf the manual valve located on the sampling line of the MEPC.107(49)-approved oily water separator is not sealed by Class,\nthe inspector should witness the operational testing of the equipment by shutting the sampling valve and stopping the\nsample water flow to the 15ppm bilge alarm. If the 15ppm bilge alarm does not activate when the effluent sample flow\nis stopped for more than five seconds, and the automatic stopping device is not triggered within twenty seconds, this is\nconsidered a failure of the oily discharge monitoring and control system and the 15ppm alarm arrangements. The inspector\nshould record a finding.\nInspectors shall, when agreed by the Chief Engineer and in full compliance with MARPOL and local environmental\nrequirements, conduct the following operational tests of the oily water separator:\n1. The equipment should be configured to circulate liquid from bilge tank to bilge tank (recirculating facility) and provide an\neffluent sample to the 15ppm bilge alarm, simulating the discharge of 15ppm bilge separator effluent overboard. When a\nsimulation of an effluent sample greater than 15ppm is applied, the inspector shall witness that the alarm is activated, and\nthat the automatic stopping device (3-way valve) stops effluent discharge overboard.\n2. If a sampling valve is provided and is not sealed by Class, the inspector shall request the accompanying engineer officer\nto close the sample valve, thereby interrupting the effluent flow to the 15ppm bilge alarm. The 15ppm bilge alarm must\nactivate within 5 seconds of the effluent sample flow being stopped, and the automatic stopping device must activate within\n20 seconds. If not, this is considered a failure of the oily discharge monitoring and control system and the 15ppm alarm\narrangements.\nInspectors should document any evidence of operational failure of system or failure to respond to an interruption of the\neffluent sample. In the latter instance, the inspector must clearly state the time at which the system responded to the\ninterruption of the effluent sample, triggering the 15ppm bilge alarm, and the time taken for the automatic stopping device to\nactivate.\nAccording to the MEPC 107(49) Chapter 6.1.1, Installation Requirements, it states that “For future inspection purposes on\nboard ship, a sampling point should be provided in a vertical section of the water effluent piping as close as is practicable to\nthe 15ppm bilge separator outlet.”\nThe requirement to install the sampling point in a vertical section of the effluent pipe is to ensure that the sample is\nrepresentative and homogeneous. If the sampling point is installed in a horizontal section of the effluent pipe, there is a risk\nthat the oil is floating at the top and will not be part of the sample.\nAlthough it may be demonstrated that sampling from a horizontal section of the water effluent piping can also result in a\nrepresentative sample, it doesn’t comply with the explicit requirement in MEPC.107(49) to have a sampling point in a vertical\nsection.\nSpecific warning signs should be posted at the overboard discharge valve of the Oily Water Separator. Effective\nsealing arrangements must be in place to prevent accidental opening, and the system should be engineered to\nprovide protection against unauthorized access or unintentional operation of the valves.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.16","internal_question_no":"05A.016","question_sort_key":5101600.102,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":77,"source_page_end":77,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.17","internal_question_no":"05A.017","question_sort_key":5101700.103,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":77,"source_page_end":77,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.18","internal_question_no":"05A.018","question_sort_key":5101800.104,"question_text":"Has a declaration been provided by the shipper as to whether the cargo is harmful to the marine environment (HME)?","guide_to_inspection":"Solid bulk cargoes shall be classified in accordance with the criteria specified in the 2012 Guidelines for the implementation\nof MARPOL Annex V MEPC. 219(63) and a declaration provided by the shipper as to whether or not they are harmful to the\nmarine environment.\nCargo residues classified as harmful to the marine environment (HME), which cannot be recovered using commonly available\nmethods for unloading, cannot be discharged into the sea. This waste must be discharged to an onshore waste reception\nfacility. MARPOL, 2017.\n(Resolution MEPC.219 (63), Guidelines for the Implementation of Marpol Annex V, 2012)\n(Resolution MEPC.278 (70) Amendments to the Annex of the International Convention for the Prevention of Pollution from\nShips, 1973, as modified by the protocol of 1978 relating thereto, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":77,"source_page_end":77,"raw_source_text":"Has a declaration been provided by the shipper as to whether the cargo is harmful to the\nmarine environment (HME)? (V)\nGuide to Inspection\nSolid bulk cargoes shall be classified in accordance with the criteria specified in the 2012 Guidelines for the implementation\nof MARPOL Annex V MEPC. 219(63) and a declaration provided by the shipper as to whether or not they are harmful to the\nmarine environment.\nCargo residues classified as harmful to the marine environment (HME), which cannot be recovered using commonly available\nmethods for unloading, cannot be discharged into the sea. This waste must be discharged to an onshore waste reception\nfacility. MARPOL, 2017.\n(Resolution MEPC.219 (63), Guidelines for the Implementation of Marpol Annex V, 2012)\n(Resolution MEPC.278 (70) Amendments to the Annex of the International Convention for the Prevention of Pollution from\nShips, 1973, as modified by the protocol of 1978 relating thereto, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.19","internal_question_no":"05A.019","question_sort_key":5101900.105,"question_text":"Has a Garbage Management Plan been provided and is the Garbage Record Book (GRB) being correctly maintained?","guide_to_inspection":"Every ship of 100 gross tonnage and above and every ship which is certified to carry 15 persons or more shall carry a garbage\nmanagement plan which the crew shall follow.\nEvery ship of 400 gross tonnage and above and every ship which is certified to carry 15 or more persons engaged in voyages to ports\nor offshore terminals under the jurisdiction of another Party to the Convention and every fixed or floating platform shall be provided\nwith a Garbage Record Book. The Garbage Record Book, whether as part of the ship’s official logbook or otherwise, shall be in the form\nspecified in the appendix to this Annex:\n1. Each discharge into the sea or to a reception facility, or a completed incineration, shall be promptly recorded in the Garbage Record\nBook and signed for on the date of discharge or incineration by the officer in charge. Each completed page of the Garbage Record Book\nshall be signed by the master of the ship. The entries in the Garbage Record Book shall be at least in English, French or Spanish. Where\nthe entries are also made in an official language of the State whose flag the ship is entitled to fly, the entries in that language shall\nprevail in case of a dispute or discrepancy.\n2. The entry for each discharge or incineration shall include date and time, position of ship, category of the garbage and the estimate\namount discharged or incinerated.\n3. The Garbage Record Book shall be kept on board the ship or the fixed or floating platform, and in such a place as to be readily\navailable for inspection at all reasonable times. This document shall be preserved for a period of at least two years from the date of the\nlast entry made in it.\n4. in the event of any discharge or accidental loss referred to in regulation 7 of this Annex and entry shall be made in the Garbage\nRecord Book, or in the case of any ship of less than 400 gross tonnage, an entry shall be made in the ship’s official logbook, of the\nlocation, circumstances of, and the reasons for the discharge orloss, details of the items discharged or lost, and the reasonable\nprecautions taken to prevent or minimize such discharge or accidental loss.\n4.1 Garbage is to be grouped into categories form the purposes of the Garbage Record Book (or ship’s official logbook) as follows:\nA- Plastics\nB- Food Wastes\nC- Domestic Wastes\nD- Cooking Oil\nE- Incinerator Ashes\nF-Operational Wastes\nG- Animal carcasses\nH- Fishing gear\nI- E-waste\n4.2 Amount of garbage\nThe amount of garbage on board should be estimated in cubic metres, if possible separately according to category.\nThe Garbage Record Book contains many references to estimated amount of garbage. It is recognized that the accuracy of estimating\namounts of garbage is left to interpretation. Volume estimates will differ before and after processing. Some processing procedures\nmay not allow for a usable estimate of volume, e.g. the continuous processing of food waste. Such factors should be taken into\nconsideration when making and interpreting entries made in a record.\n(MARPOL, 2017)\n(Resolution MEPC.220 (63), Guidelines for the Development of Garbage Management Plans, 2012)\n(Resolution MEPC.295 (71), Guidelines for the Implementation of MARPOL Annex V, 2017)\nGarbage collected throughout the ship should be delivered to designated processing or storage locations. Cleaning and disinfecting of\ngarbage storage location are both preventative and remedial pest control methods that should be applied regularly in garbage storage\nareas.\n(GUIDELINES FOR THE IMPLEMENTATION OF MARPOL ANNEX V, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":77,"source_page_end":78,"raw_source_text":"Has a Garbage Management Plan been provided and is the Garbage Record Book (GRB) being\ncorrectly maintained? (V)\nGuide to Inspection\nEvery ship of 100 gross tonnage and above and every ship which is certified to carry 15 persons or more shall carry a garbage\nmanagement plan which the crew shall follow.\nEvery ship of 400 gross tonnage and above and every ship which is certified to carry 15 or more persons engaged in voyages to ports\nor offshore terminals under the jurisdiction of another Party to the Convention and every fixed or floating platform shall be provided\nwith a Garbage Record Book. The Garbage Record Book, whether as part of the ship’s official logbook or otherwise, shall be in the form\nspecified in the appendix to this Annex:\n1. Each discharge into the sea or to a reception facility, or a completed incineration, shall be promptly recorded in the Garbage Record\nBook and signed for on the date of discharge or incineration by the officer in charge. Each completed page of the Garbage Record Book\nshall be signed by the master of the ship. The entries in the Garbage Record Book shall be at least in English, French or Spanish. Where\nthe entries are also made in an official language of the State whose flag the ship is entitled to fly, the entries in that language shall\nprevail in case of a dispute or discrepancy.\n2. The entry for each discharge or incineration shall include date and time, position of ship, category of the garbage and the estimate\namount discharged or incinerated.\n3. The Garbage Record Book shall be kept on board the ship or the fixed or floating platform, and in such a place as to be readily\navailable for inspection at all reasonable times. This document shall be preserved for a period of at least two years from the date of the\nlast entry made in it.\n4. in the event of any discharge or accidental loss referred to in regulation 7 of this Annex and entry shall be made in the Garbage\nRecord Book, or in the case of any ship of less than 400 gross tonnage, an entry shall be made in the ship’s official logbook, of the\nlocation, circumstances of, and the reasons for the discharge orloss, details of the items discharged or lost, and the reasonable\nprecautions taken to prevent or minimize such discharge or accidental loss.\n4.1 Garbage is to be grouped into categories form the purposes of the Garbage Record Book (or ship’s official logbook) as follows:\nA- Plastics\nB- Food Wastes\nC- Domestic Wastes\nD- Cooking Oil\nE- Incinerator Ashes\nF-Operational Wastes\nG- Animal carcasses\nH- Fishing gear\nI- E-waste\n4.2 Amount of garbage\nThe amount of garbage on board should be estimated in cubic metres, if possible separately according to category.\nThe Garbage Record Book contains many references to estimated amount of garbage. It is recognized that the accuracy of estimating\namounts of garbage is left to interpretation. Volume estimates will differ before and after processing. Some processing procedures\nmay not allow for a usable estimate of volume, e.g. the continuous processing of food waste. Such factors should be taken into\nconsideration when making and interpreting entries made in a record.\n(MARPOL, 2017)\n(Resolution MEPC.220 (63), Guidelines for the Development of Garbage Management Plans, 2012)\n(Resolution MEPC.295 (71), Guidelines for the Implementation of MARPOL Annex V, 2017)\nGarbage collected throughout the ship should be delivered to designated processing or storage locations. Cleaning and disinfecting of\ngarbage storage location are both preventative and remedial pest control methods that should be applied regularly in garbage storage\nareas.\n(GUIDELINES FOR THE IMPLEMENTATION OF MARPOL ANNEX V, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.20","internal_question_no":"05A.020","question_sort_key":5102000.106,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":78,"source_page_end":78,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.21","internal_question_no":"05A.021","question_sort_key":5102100.107,"question_text":"Has a ship-specific Energy Efficiency Management Plan been provided to the vessel?","guide_to_inspection":"To support ships’ energy performance and efficiency objectives, the IMO has developed the SEEMP. This three-part\noperational measure establishes a cost-effective mechanism for improving ship energy efficiency over time.\nSEEMP Part I:\nCame into force on January 1, 2013.\nRequired all ships over 400 GT making international voyages to have SEEMP documentation on-board.\nSEEMP PART II\nCame into effect on January 1, 2019, as part of the IMO Data Collection System (DCS).\nRequired every ship over 5,000 GT to collect data and report on their fuel oil consumption.\nSEEMP Part II must be verified by the relevant flag administration, or any organization duly authorized by it.\nSEEMP PART III\nCame into effect on January 1, 2023, and concerns ships’ Carbon Intensity Indicator (CII) and ratings.\nRequires ships over 5,000 GT (that fall into one of the categories listed in MARPOL Annex VI, regulation 26) to describe and\nsupport the ship’s carbon intensity objectives, using data from the IMO DCS to assess their performance.\nContains a ship’s CII calculation methodology, the required CII values for the next three years, a three-year implementation\nplan, and self-evaluation and improvement procedures.\nMust be verified by the relevant flag administration or any organization duly authorized by it.\nThe SEEMP Part III is designed to assist companies in achieving the required Carbon Intensity Indicator (CII). In relation to\nthis annual rating, the SEEMP Part III is a mandatory, ship-specific document that outlines the plan to improve the CII, and\nconsequently, the vessel’s operational energy efficiency, over the next three years.\nThe SEEMP Part III is a dynamic document that is subject to regular updates and revisions, reflecting changes in\nperformance and required measures. It must be verified and kept on board the respective vessel from January 1, 2023, along\nwith the Confirmation of Compliance (CoC)\nConnection between DCS, CII and SEEMP Part III\nStarting in 2024, the CII must be calculated and reported to the DCS verifier, along with the aggregated DCS data for the\nprevious year, including any correction factors and voyage adjustments. The attained CII and the environmental rating (A to E)\nwill be noted on the DCS Statement of Compliance (SoC), which is required to be kept on board for five years.\nIn case of a D rating for three consecutive years or one E rating, the SEEMP Part III must be updated with a Corrective Action\nPlan and verified before the DCS SoC can be issued. The Corrective Action Plan should consist of an analysis of why the\nrequired CII was not achieved and include a revised implementation plan.\n(MEPC.346(78) 2022 )\nSEEMP Part III is a dynamic document that needs to be updated regularly with prevailing fuel consumption data. This allows\nthe vessel’s manager to tangibly track the CII performance and the effectiveness of the ship’s energy efficiency measures.\nThe SEEMP Part III plan provides the information needed to assess the operational carbon intensity (CII) of the ship.\nRegulation 26.3.3 of Annex VI requires SEEMP Part III to be subject to periodical company audits, which should be\nundertaken at least every three years.\nThe scope for such company audits is outlined in Resolution MEPC.347(78) – Guidelines for the Verification and Company\nAudits by the Administration of Part III of the Ship Energy Efficiency Management Plan (SEEMP).\nCompany audits are to be undertaken within a period of six months after the issue of the Statement of Compliance related to\nfuel oil consumption reporting and operational carbon intensity rating, as required by MARPOL Annex VI, Regulation 6.6.4.\nClassification Societies can act on behalf of the flag Administration to perform company audits. The Class should issue\na statement confirming that the periodical company audit has been conducted to demonstrate compliance with this\nrequirement.\nAn additional verification shall be carried to a ship rated as D for three consecutive years, to ensure that a plan of corrective\nactions has been established. A company audit should take place during the third year, after 2 consecutive years, rated as D.\nAn additional verification shall be carried to a ship rated as E, to ensure that a plan of corrective actions has been established.\nA company audit, in conjunction with a shipboard audit, should take place during the immediate year after, being rated as E.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":78,"source_page_end":79,"raw_source_text":"Has a ship-specific Energy Efficiency Management Plan been provided to the vessel?\nGuide to Inspection\nTo support ships’ energy performance and efficiency objectives, the IMO has developed the SEEMP. This three-part\noperational measure establishes a cost-effective mechanism for improving ship energy efficiency over time.\nSEEMP Part I:\nCame into force on January 1, 2013.\nRequired all ships over 400 GT making international voyages to have SEEMP documentation on-board.\nSEEMP PART II\nCame into effect on January 1, 2019, as part of the IMO Data Collection System (DCS).\nRequired every ship over 5,000 GT to collect data and report on their fuel oil consumption.\nSEEMP Part II must be verified by the relevant flag administration, or any organization duly authorized by it.\nSEEMP PART III\nCame into effect on January 1, 2023, and concerns ships’ Carbon Intensity Indicator (CII) and ratings.\nRequires ships over 5,000 GT (that fall into one of the categories listed in MARPOL Annex VI, regulation 26) to describe and\nsupport the ship’s carbon intensity objectives, using data from the IMO DCS to assess their performance.\nContains a ship’s CII calculation methodology, the required CII values for the next three years, a three-year implementation\nplan, and self-evaluation and improvement procedures.\nMust be verified by the relevant flag administration or any organization duly authorized by it.\nThe SEEMP Part III is designed to assist companies in achieving the required Carbon Intensity Indicator (CII). In relation to\nthis annual rating, the SEEMP Part III is a mandatory, ship-specific document that outlines the plan to improve the CII, and\nconsequently, the vessel’s operational energy efficiency, over the next three years.\nThe SEEMP Part III is a dynamic document that is subject to regular updates and revisions, reflecting changes in\nperformance and required measures. It must be verified and kept on board the respective vessel from January 1, 2023, along\nwith the Confirmation of Compliance (CoC)\nConnection between DCS, CII and SEEMP Part III\nStarting in 2024, the CII must be calculated and reported to the DCS verifier, along with the aggregated DCS data for the\nprevious year, including any correction factors and voyage adjustments. The attained CII and the environmental rating (A to E)\nwill be noted on the DCS Statement of Compliance (SoC), which is required to be kept on board for five years.\nIn case of a D rating for three consecutive years or one E rating, the SEEMP Part III must be updated with a Corrective Action\nPlan and verified before the DCS SoC can be issued. The Corrective Action Plan should consist of an analysis of why the\nrequired CII was not achieved and include a revised implementation plan.\n(MEPC.346(78) 2022 )\nSEEMP Part III is a dynamic document that needs to be updated regularly with prevailing fuel consumption data. This allows\nthe vessel’s manager to tangibly track the CII performance and the effectiveness of the ship’s energy efficiency measures.\nThe SEEMP Part III plan provides the information needed to assess the operational carbon intensity (CII) of the ship.\nRegulation 26.3.3 of Annex VI requires SEEMP Part III to be subject to periodical company audits, which should be\nundertaken at least every three years.\nThe scope for such company audits is outlined in Resolution MEPC.347(78) – Guidelines for the Verification and Company\nAudits by the Administration of Part III of the Ship Energy Efficiency Management Plan (SEEMP).\nCompany audits are to be undertaken within a period of six months after the issue of the Statement of Compliance related to\nfuel oil consumption reporting and operational carbon intensity rating, as required by MARPOL Annex VI, Regulation 6.6.4.\nClassification Societies can act on behalf of the flag Administration to perform company audits. The Class should issue\na statement confirming that the periodical company audit has been conducted to demonstrate compliance with this\nrequirement.\nAn additional verification shall be carried to a ship rated as D for three consecutive years, to ensure that a plan of corrective\nactions has been established. A company audit should take place during the third year, after 2 consecutive years, rated as D.\nAn additional verification shall be carried to a ship rated as E, to ensure that a plan of corrective actions has been established.\nA company audit, in conjunction with a shipboard audit, should take place during the immediate year after, being rated as E.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.22","internal_question_no":"05A.022","question_sort_key":5102200.108,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":79,"source_page_end":79,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.23","internal_question_no":"05A.023","question_sort_key":5102300.109,"question_text":"If the vessel has an Exhaust Gas Cleaning System (scrubber system), is it in good working order, are the engineers familiar with its safe operation, and have procedures been incorporated into the Safety Management System?","guide_to_inspection":"There are three types of exhaust gas cleaning systems at present – open loop system, closed loop system and Hybrid\nsystem. Record the type of exhaust gas cleaning system in comments.\nRecord Finding if there was soot on the water surface, which have been traced to the wash water discharge from vessels.\nCorrosion of overboard distance piece attached to the hull on SOX scrubber discharge water line can result in water ingress\ninto areas such as the engine room, ballast tanks and cargo holds. Absence of or poor application of protective coatings on\nthe inside of the pipe and at the welds, along with poor application of paint on hull plating near the wash water discharge\nwere identified as the causes of accelerated corrosion. Rightship recommends that the vessel manager implement a method\nof monitoring the internal condition of distance piece in the PMS.\nCrew should be fully trained to handle the scrubber system and hazardous chemicals used for the process. They should also\nbe trained to deal with medical emergencies. Hazardous chemicals are used in a number of Exhaust Gas Cleaning System\n(EGCS) and adequate controls should be put in place to protect the ship’s staff.\nThere is also a possibility of further hazardous chemicals and compounds (such as ammonium bisulphate in selective\ncatalytic reduction (SCR) systems) being generated. These will require robust procedures and crew training, as well as\nadequate signage and personal protective equipment (PPE). Crew training should cover the normal operation of the scrubber\nsystem, including bunkering of any chemicals (consumables), calibration of sensors and routine maintenance, as well as the\nprocedures to be followed in case of system failure and deviation from normal operation.\n(Your options for emissions compliance Guidance for shipowners and\noperators on the Annex VI SOx and NOx regulations, 2015)\nThe maintenance, calibration, cleaning, and chemical handling of the exhaust gas cleaning system shall be incorporated in\nthe plan maintenance system. The system shall be approved by the classification society.\nEGCS malfunction:\nAny EGCS malfunction should be noted in the EGCS record book and engine room logbook, including the date and time of\nmalfunction, if and how it was resolved, and any follow-up action. The ship manager should be informed, as should the flag\nstate administration, as necessary.\nEmissions may be exceeded in the short term when a sudden change in the exhaust gas flow rate changes the EGCS\ndynamic response. The ECS technical manual will specify the typical operating conditions that may result when emissions\nare exceeded for a short time.\nRepetitive malfunctions and any malfunctions that last more than an hour should be reported to the flag and port state, along\nwith an explanation of the steps the operator is taking to address the failure. At their discretion, the flag or port state may take\nthis information and other relevant circumstances into account when deciding what action to take.\nIf non-compliance cannot be settled resolved within an hour, changeover to compliant fuel should be considered and the EGCS\nstopped. Flag and or port state should be consulted. All relevant entries should be made in engine room/deck logbooks.\n( Engine Room Procedure Guide 2024)\nMalfunctions of EGCS lasting over an hour should be reported to the flag and port state administrations. Sometimes, malfunctions\ngo undetected due to poor maintenance, as monitoring equipment may not register increased SO2 levels.\nZero or negative SO2 readings don’t always indicate analyzer failure; they can be within calibration tolerance. Low sulphur fuel, low\nengine load, and high wash water flow typically result in low SO2 levels.\nHowever, zero or negative readings should be scrutinized. Indicators of false readings include irritating exhaust odors, stable\nreadings despite wash water adjustments, and CO2 levels below 5%. High sulphur fuel should show noticeable SO2 levels. Regular\nself-checks and error message reviews are crucial.\nFor suspected false readings, follow the manufacturer’s corrective actions. Check for leaks in the measuring system, ensure proper\ncalibration, and avoid systematic errors.\nRecommendations:\n> Be alert to prolonged zero or negative readings and perform plausibility checks.\n> Perform a validation test: Validate by increasing engine load and decreasing wash water flow; if SO2 doesn’t increase, service\nthe analyzer.\n> Follow strict service, maintenance, and calibration procedures to minimize malfunctions.\n(DNV Technical and Regulatory News No.25/2024)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":79,"source_page_end":80,"raw_source_text":"If the vessel has an Exhaust Gas Cleaning System (scrubber system), is it in good working order, are the\nengineers familiar with its safe operation, and have procedures been incorporated into the Safety\nManagement System?\nGuide to Inspection\nThere are three types of exhaust gas cleaning systems at present – open loop system, closed loop system and Hybrid\nsystem. Record the type of exhaust gas cleaning system in comments.\nRecord Finding if there was soot on the water surface, which have been traced to the wash water discharge from vessels.\nCorrosion of overboard distance piece attached to the hull on SOX scrubber discharge water line can result in water ingress\ninto areas such as the engine room, ballast tanks and cargo holds. Absence of or poor application of protective coatings on\nthe inside of the pipe and at the welds, along with poor application of paint on hull plating near the wash water discharge\nwere identified as the causes of accelerated corrosion. Rightship recommends that the vessel manager implement a method\nof monitoring the internal condition of distance piece in the PMS.\nCrew should be fully trained to handle the scrubber system and hazardous chemicals used for the process. They should also\nbe trained to deal with medical emergencies. Hazardous chemicals are used in a number of Exhaust Gas Cleaning System\n(EGCS) and adequate controls should be put in place to protect the ship’s staff.\nThere is also a possibility of further hazardous chemicals and compounds (such as ammonium bisulphate in selective\ncatalytic reduction (SCR) systems) being generated. These will require robust procedures and crew training, as well as\nadequate signage and personal protective equipment (PPE). Crew training should cover the normal operation of the scrubber\nsystem, including bunkering of any chemicals (consumables), calibration of sensors and routine maintenance, as well as the\nprocedures to be followed in case of system failure and deviation from normal operation.\n(Your options for emissions compliance Guidance for shipowners and\noperators on the Annex VI SOx and NOx regulations, 2015)\nThe maintenance, calibration, cleaning, and chemical handling of the exhaust gas cleaning system shall be incorporated in\nthe plan maintenance system. The system shall be approved by the classification society.\nEGCS malfunction:\nAny EGCS malfunction should be noted in the EGCS record book and engine room logbook, including the date and time of\nmalfunction, if and how it was resolved, and any follow-up action. The ship manager should be informed, as should the flag\nstate administration, as necessary.\nEmissions may be exceeded in the short term when a sudden change in the exhaust gas flow rate changes the EGCS\ndynamic response. The ECS technical manual will specify the typical operating conditions that may result when emissions\nare exceeded for a short time.\nRepetitive malfunctions and any malfunctions that last more than an hour should be reported to the flag and port state, along\nwith an explanation of the steps the operator is taking to address the failure. At their discretion, the flag or port state may take\nthis information and other relevant circumstances into account when deciding what action to take.\nIf non-compliance cannot be settled resolved within an hour, changeover to compliant fuel should be considered and the EGCS\nstopped. Flag and or port state should be consulted. All relevant entries should be made in engine room/deck logbooks.\n( Engine Room Procedure Guide 2024)\nMalfunctions of EGCS lasting over an hour should be reported to the flag and port state administrations. Sometimes, malfunctions\ngo undetected due to poor maintenance, as monitoring equipment may not register increased SO2 levels.\nZero or negative SO2 readings don’t always indicate analyzer failure; they can be within calibration tolerance. Low sulphur fuel, low\nengine load, and high wash water flow typically result in low SO2 levels.\nHowever, zero or negative readings should be scrutinized. Indicators of false readings include irritating exhaust odors, stable\nreadings despite wash water adjustments, and CO2 levels below 5%. High sulphur fuel should show noticeable SO2 levels. Regular\nself-checks and error message reviews are crucial.\nFor suspected false readings, follow the manufacturer’s corrective actions. Check for leaks in the measuring system, ensure proper\ncalibration, and avoid systematic errors.\nRecommendations:\n> Be alert to prolonged zero or negative readings and perform plausibility checks.\n> Perform a validation test: Validate by increasing engine load and decreasing wash water flow; if SO2 doesn’t increase, service\nthe analyzer.\n> Follow strict service, maintenance, and calibration procedures to minimize malfunctions.\n(DNV Technical and Regulatory News No.25/2024)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.24","internal_question_no":"05A.024","question_sort_key":5102400.11,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":80,"source_page_end":80,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.25","internal_question_no":"05A.025","question_sort_key":5102500.111,"question_text":"Are the ballast pumping systems, including their associated instruments, controls, valves, pipework, and the control panel (including pressure gauges, draft gauges, and the remote control system), in good working order and is there recorded evidence of regular inspection?","guide_to_inspection":"The maintenance and testing of the ballast valves should be incorporated into the PMS.\nValve Remote Control System: This refers to devices that utilize hydraulic oil pressure, pneumatic pressure, and/or electricity\nas power sources. These devices enable remote centralized control and position display of valves within the ship’s piping\nsystems, all from the control console.\nThe controls and indicators of the Ballast System should be accurate and fully operational, including, where fitted:\n> Monitoring of draft, trim, and list\n> Control and monitoring of ballast pumps and associated plant\n> Control of ballast system valves and indication of their status\n> Information mimics/displays of the ballast system\nAll pressure, temperature, and level sensors of the ballast system should be periodically verified for accuracy.\nIncorrect Valve Position Indication: The primary function of the hydraulically controlled valve is to enable remote operation.\nBallast control panels for such valves are equipped with position indicators that display the current position of the valve\n(Open or Shut). An incorrect position displayed by the indicator can lead to confusion. This may cause the officer in charge of\ncargo operation to proceed with ballast operation without knowing the actual position of the valve.\nCommon Causes for Incorrect Valve Position Indication:\nThe following are the most common causes for incorrect position indication:\n> Defective flow meter\n> Defective pressure switch\n> Problems with the indicator panel\n> Slow valve movement\nOnce the signal is given to operate a hydraulic valve from the ballast control panel, the valve should fully open or shut within a\ngiven time. A delay in the operating timing of the valve can be caused by:\n> Defective control valve operation\n> Clogged flow reducer\n> Clogged filters\n> Low oil pressure\n> Low oil temperature\n> Damaged valve actuator\nValve Opening/Closing Time: This refers to the duration the actuator of the Valve Remote Control System takes to drive the\nvalves into an open or closed position.\nIt is recommended that all shipside valves and main valves be opened out and overhauled, repaired and surveyed at dry dock\nto ensure their correct operation and tightness.\nOperating time of the power operated ballast valves should be checked regularly, and the manufacturers guidance should be\nfollowed for optimum opening and closing times of the ballast valves.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":80,"source_page_end":80,"raw_source_text":"Are the ballast pumping systems, including their associated instruments, controls, valves, pipework, and the\ncontrol panel (including pressure gauges, draft gauges, and the remote control system), in good working order\nand is there recorded evidence of regular inspection?(V)\nGuide to Inspection\nThe maintenance and testing of the ballast valves should be incorporated into the PMS.\nValve Remote Control System: This refers to devices that utilize hydraulic oil pressure, pneumatic pressure, and/or electricity\nas power sources. These devices enable remote centralized control and position display of valves within the ship’s piping\nsystems, all from the control console.\nThe controls and indicators of the Ballast System should be accurate and fully operational, including, where fitted:\n> Monitoring of draft, trim, and list\n> Control and monitoring of ballast pumps and associated plant\n> Control of ballast system valves and indication of their status\n> Information mimics/displays of the ballast system\nAll pressure, temperature, and level sensors of the ballast system should be periodically verified for accuracy.\nIncorrect Valve Position Indication: The primary function of the hydraulically controlled valve is to enable remote operation.\nBallast control panels for such valves are equipped with position indicators that display the current position of the valve\n(Open or Shut). An incorrect position displayed by the indicator can lead to confusion. This may cause the officer in charge of\ncargo operation to proceed with ballast operation without knowing the actual position of the valve.\nCommon Causes for Incorrect Valve Position Indication:\nThe following are the most common causes for incorrect position indication:\n> Defective flow meter\n> Defective pressure switch\n> Problems with the indicator panel\n> Slow valve movement\nOnce the signal is given to operate a hydraulic valve from the ballast control panel, the valve should fully open or shut within a\ngiven time. A delay in the operating timing of the valve can be caused by:\n> Defective control valve operation\n> Clogged flow reducer\n> Clogged filters\n> Low oil pressure\n> Low oil temperature\n> Damaged valve actuator\nValve Opening/Closing Time: This refers to the duration the actuator of the Valve Remote Control System takes to drive the\nvalves into an open or closed position.\nIt is recommended that all shipside valves and main valves be opened out and overhauled, repaired and surveyed at dry dock\nto ensure their correct operation and tightness.\nOperating time of the power operated ballast valves should be checked regularly, and the manufacturers guidance should be\nfollowed for optimum opening and closing times of the ballast valves.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.26","internal_question_no":"05A.026","question_sort_key":5102600.112,"question_text":"Are bunker and ballast tank manholes maintained in good condition?","guide_to_inspection":"The gaskets and fastening bolts should be fitted in their original condition and maintained in good condition.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":81,"source_page_end":81,"raw_source_text":"Are bunker and ballast tank manholes maintained in good condition?\nGuide to Inspection\nThe gaskets and fastening bolts should be fitted in their original condition and maintained in good condition.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"05A","section_number":5,"section_letter":"A","section_title":"Pollution Prevention and Control","printed_question_no":"5.27","internal_question_no":"05A.027","question_sort_key":5102700.113,"question_text":"Are the crew members familiar with the operation and maintenance of the sewage treatment plant, and is the sewage treatment plant, including its associated piping, discharge pumps, and air blowers, in good condition?","guide_to_inspection":"The sewage regulations prohibit the discharge of sewage into the sea, except when the ship has in operation an approved\nsewage treatment plant; is discharging comminuted (or macerated) and disinfected sewage at a distance of more than three\nnautical miles from the nearest land; or is discharging untreated sewage from a holding tank at a prescribed rate and at a\ndistance of more than 12 nautical miles from the nearest land. The sewage regulations also include standards for discharge\nconnections to facilitate the disposal of sewage from ship to shore.\nEngineer officers should be familiar with the operation and maintenance of the sewage treatment plant, following the\nmanufacturer’s guidelines. The effectiveness of the plant’s aeration and air blowers can be verified by observing fine air\nbubbles in the sludge return line.\nThe final stage of water treatment incorporates a chlorinator before the water is pumped overboard. The chlorinator could be\neither a tablet dosing type or a chemical injection type.\nIn the tablet-based chlorinator, clean water directly contacts the chlorine tablets, forming a chlorine solution. The chlorinator\nis equipped with cylinders for tablet insertion. A sufficient number of tablets of adequate dimensions that can be inserted\nwithout breaking and as recommended by the manufacturer, should be used.\nIn the chemical pump type, a predetermined quantity of Sodium Hypochlorite(NaOCl) is injected into the sterilisation/\nchlorination tank using a diaphragm-type reciprocating pump.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":81,"source_page_end":81,"raw_source_text":"Are the crew members familiar with the operation and maintenance of the sewage treatment plant, and\nis the sewage treatment plant, including its associated piping, discharge pumps, and air blowers,\nin good condition?\nGuide to Inspection\nThe sewage regulations prohibit the discharge of sewage into the sea, except when the ship has in operation an approved\nsewage treatment plant; is discharging comminuted (or macerated) and disinfected sewage at a distance of more than three\nnautical miles from the nearest land; or is discharging untreated sewage from a holding tank at a prescribed rate and at a\ndistance of more than 12 nautical miles from the nearest land. The sewage regulations also include standards for discharge\nconnections to facilitate the disposal of sewage from ship to shore.\nEngineer officers should be familiar with the operation and maintenance of the sewage treatment plant, following the\nmanufacturer’s guidelines. The effectiveness of the plant’s aeration and air blowers can be verified by observing fine air\nbubbles in the sludge return line.\nThe final stage of water treatment incorporates a chlorinator before the water is pumped overboard. The chlorinator could be\neither a tablet dosing type or a chemical injection type.\nIn the tablet-based chlorinator, clean water directly contacts the chlorine tablets, forming a chlorine solution. The chlorinator\nis equipped with cylinders for tablet insertion. A sufficient number of tablets of adequate dimensions that can be inserted\nwithout breaking and as recommended by the manufacturer, should be used.\nIn the chemical pump type, a predetermined quantity of Sodium Hypochlorite(NaOCl) is injected into the sterilisation/\nchlorination tank using a diaphragm-type reciprocating pump.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.1","internal_question_no":"06A.001","question_sort_key":6100100.114,"question_text":"Is the vessel free of any hull repairs unreported to class?","guide_to_inspection":"Record a Finding if documents or visual evidence indicated that unauthorised hull repairs have been carried out.\nThe vessel’s manager may engage a “Riding Crew” consisting of a qualified welder and fitters who carry out repairs and steel\nrenewal at sea. The Riding Crew may be involved in welding fractures and replacing deck plate and hatch coaming in various\nlocations, including cargo holds and ballast tanks. Many repairs carried out on voyages are not brought to the attention of the\nclass society and are not always carried out in a professional way.\nIt is the responsibility of the shipowner to maintain and repair the vessel in periods between regular surveys. Moreover,\nthe shipowner is required to inform the corresponding Classification Society as soon as any damage or defect which may\naffect conformance with Classification rules is discovered. There is no precise definition of what deficiencies are relevant\nin this respect. In general, these would be defects which diminish the structural capability of the hull, breach the watertight\nintegrity of tanks or the hull, or impair redundancy or normal operation of a vessel’s propulsion, steering, power generation,\nauxiliary machinery, and associated systems. In case of doubt as to whether a particular deficiency warrants Class attention,\nshipowners should contact their Classification Society for clarification.\n(Onboard Repairs - Compliance with Class and Statutory Requirements - A P&I Perspective, 2017)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":82,"source_page_end":82,"raw_source_text":"Is the vessel free of any hull repairs unreported to class? (V)\nGuide to Inspection\nRecord a Finding if documents or visual evidence indicated that unauthorised hull repairs have been carried out.\nThe vessel’s manager may engage a “Riding Crew” consisting of a qualified welder and fitters who carry out repairs and steel\nrenewal at sea. The Riding Crew may be involved in welding fractures and replacing deck plate and hatch coaming in various\nlocations, including cargo holds and ballast tanks. Many repairs carried out on voyages are not brought to the attention of the\nclass society and are not always carried out in a professional way.\nIt is the responsibility of the shipowner to maintain and repair the vessel in periods between regular surveys. Moreover,\nthe shipowner is required to inform the corresponding Classification Society as soon as any damage or defect which may\naffect conformance with Classification rules is discovered. There is no precise definition of what deficiencies are relevant\nin this respect. In general, these would be defects which diminish the structural capability of the hull, breach the watertight\nintegrity of tanks or the hull, or impair redundancy or normal operation of a vessel’s propulsion, steering, power generation,\nauxiliary machinery, and associated systems. In case of doubt as to whether a particular deficiency warrants Class attention,\nshipowners should contact their Classification Society for clarification.\n(Onboard Repairs - Compliance with Class and Statutory Requirements - A P&I Perspective, 2017)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.2","internal_question_no":"06A.002","question_sort_key":6100200.115,"question_text":"Does the SMS include procedures and instructions for regular inspection of cargo holds, ballast tanks, void spaces, trunks, duct keel and cofferdams by the ship’s personnel and are records maintained?","guide_to_inspection":"Record of inspection, photo and/or video evidence of such inspection shall be available. Record a Finding:\n1. When the inspection report is not available, or\n2. When inspection report was not supported with photos and /or video evidence.\nAfter every discharge and each cleaning, holds should be formally inspected by the Master or Chief Officer. The ballast tanks,\nvoid spaces, cofferdams, and duct keel should be inspected at least annually. Ballast tanks and void spaces adjacent to grab or\nbulldozer’s damage shall be inspected after completion of the discharge. This inspection should be recorded with photographs.\nThe inspection plan and records should at least cover the following:\n> Framing of the holds – damaged and ‘tripped’ brackets\n> Condition of bulkhead coatings on the holds\n> Condition of hatch covers, trackways, compression bars, channel drainage, hatch rubbers, cross, hatch drain valve and\nside cleats\n> Hatch and hold vents and watertight lids, including access hatch lids, rubber packing and closing cleats and dogs\n> Tank top, any damage\n> Condition of coating in ballast tanks, void space, cofferdam, and duct keel\n> Condition of tank top double bottom or side tank access lid, condition and the fitting of the gaskets, condition of nuts\n> Condition of hold ladders, platforms and handrails\n> Condition of hold piping, air vent and water ballast sounding lines, and piping protection brackets\n> Condition of bilge wells, including bilge covers, strum boxes, and bilge well valves, including non-return valves\n> Condition of bilge high-level alarms\n> Condition of lights and light fittings.\nSelf-unloading vessels that handle bulk materials may utilize linings specifically designed to reduce friction between the\ncargo and the beds or chutes. This design facilitates and enhances the mass flow of materials, increasing the rate of flow\nby preventing blockages, build-ups, and funnel flow. The frequency of lining replacement can depend on various factors,\nincluding the type of cargo, the frequency of operations, and environmental conditions. It is recommended that the lining be\nmaintained in accordance with the manufacturer’s guidelines. If linings are provided, they should be regularly inspected and\nmaintained as an integral part of routine vessel maintenance.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":82,"source_page_end":82,"raw_source_text":"Does the SMS include procedures and instructions for regular inspection of cargo holds, ballast tanks, void\nspaces, trunks, duct keel and cofferdams by the ship’s personnel and are records maintained? (V)\nGuide to Inspection\nRecord of inspection, photo and/or video evidence of such inspection shall be available. Record a Finding:\n1. When the inspection report is not available, or\n2. When inspection report was not supported with photos and /or video evidence.\nAfter every discharge and each cleaning, holds should be formally inspected by the Master or Chief Officer. The ballast tanks,\nvoid spaces, cofferdams, and duct keel should be inspected at least annually. Ballast tanks and void spaces adjacent to grab or\nbulldozer’s damage shall be inspected after completion of the discharge. This inspection should be recorded with photographs.\nThe inspection plan and records should at least cover the following:\n> Framing of the holds – damaged and ‘tripped’ brackets\n> Condition of bulkhead coatings on the holds\n> Condition of hatch covers, trackways, compression bars, channel drainage, hatch rubbers, cross, hatch drain valve and\nside cleats\n> Hatch and hold vents and watertight lids, including access hatch lids, rubber packing and closing cleats and dogs\n> Tank top, any damage\n> Condition of coating in ballast tanks, void space, cofferdam, and duct keel\n> Condition of tank top double bottom or side tank access lid, condition and the fitting of the gaskets, condition of nuts\n> Condition of hold ladders, platforms and handrails\n> Condition of hold piping, air vent and water ballast sounding lines, and piping protection brackets\n> Condition of bilge wells, including bilge covers, strum boxes, and bilge well valves, including non-return valves\n> Condition of bilge high-level alarms\n> Condition of lights and light fittings.\nSelf-unloading vessels that handle bulk materials may utilize linings specifically designed to reduce friction between the\ncargo and the beds or chutes. This design facilitates and enhances the mass flow of materials, increasing the rate of flow\nby preventing blockages, build-ups, and funnel flow. The frequency of lining replacement can depend on various factors,\nincluding the type of cargo, the frequency of operations, and environmental conditions. It is recommended that the lining be\nmaintained in accordance with the manufacturer’s guidelines. If linings are provided, they should be regularly inspected and\nmaintained as an integral part of routine vessel maintenance.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.3","internal_question_no":"06A.003","question_sort_key":6100300.116,"question_text":"Is the Enhanced Survey report file adequately maintained and does the condition evaluation report confirm the fitness of the ship for its intended service for the next five years?","guide_to_inspection":"Record the tank coating condition in comment. This question must be answered N/A if the Class certificate indicates the vessel\nas a General Cargo Ship.\nBulk carriers and oil tankers shall have a survey report file and supporting documents complying with paragraphs 6.2 and 6.3\nof annex A and annex B of resolution A.744(18) – Guidelines on the enhanced programme of inspections during surveys of bulk\ncarriers and oil tankers.\nNote: refer to the requirements of survey report file and supporting documents for bulk carriers and oil tankers as referred to in\nparagraphs 6.2 and 6.3 of annex A/annex B, part A/part B, 2011 ESP Code.\n(SOLAS 1974, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":83,"source_page_end":83,"raw_source_text":"Is the Enhanced Survey report file adequately maintained and does the condition evaluation report\nconfirm the fitness of the ship for its intended service for the next five years? (M)\nGuide to Inspection\nRecord the tank coating condition in comment. This question must be answered N/A if the Class certificate indicates the vessel\nas a General Cargo Ship.\nBulk carriers and oil tankers shall have a survey report file and supporting documents complying with paragraphs 6.2 and 6.3\nof annex A and annex B of resolution A.744(18) – Guidelines on the enhanced programme of inspections during surveys of bulk\ncarriers and oil tankers.\nNote: refer to the requirements of survey report file and supporting documents for bulk carriers and oil tankers as referred to in\nparagraphs 6.2 and 6.3 of annex A/annex B, part A/part B, 2011 ESP Code.\n(SOLAS 1974, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.4","internal_question_no":"06A.004","question_sort_key":6100400.117,"question_text":"Are the access points to cargo holds, ballast tanks, and void spaces including vertical ladders, spiral ladders, rungs, stations, and platforms being maintained and in good order?","guide_to_inspection":"Corrosion wastage affects the structural safety. Record a Finding if vertical ladders, spiral ladders, rungs, station, and platform\nare found damaged or corroded.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":83,"source_page_end":83,"raw_source_text":"Are the access points to cargo holds, ballast tanks, and void spaces including vertical ladders, spiral ladders,\nrungs, stations, and platforms being maintained and in good order? (V)\nGuide to Inspection\nCorrosion wastage affects the structural safety. Record a Finding if vertical ladders, spiral ladders, rungs, station, and platform\nare found damaged or corroded.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.5","internal_question_no":"06A.005","question_sort_key":6100500.118,"question_text":"Are the air pipes and sounding pipes in the cargo holds and void spaces in good condition?","guide_to_inspection":"Deck sounding pipes pass through the weather deck and are fitted with screw-down caps. Sounding pipes for engine room\ndouble-bottom tanks are fitted with counterweight self-closing cocks. It is imperative that sounding pipe caps or cocks be kept\nshut and well maintained.\nPipes passing through a dry cargo space must be inspected for physical damage after the completion of discharging\noperations. It is advisable to open and inspect air pipe headers on the exposed weather deck once every five years, following the\nfirst special survey. This is necessary because corrosion on the inside of an air pipe header will not be noticeable externally. To\nextend the life of air pipe headers, they should be galvanised.\nScrew-down caps are fitted to the top of sounding pipes. These caps should never be mislaid or replaced with wooden plugs.\nThe self-closing cocks on engine room sounding pipes should never be tied open.\n(A Master’s Guide to Ship’s Piping, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":83,"source_page_end":83,"raw_source_text":"Are the air pipes and sounding pipes in the cargo holds and void spaces in good condition? (V)\nGuide to Inspection\nDeck sounding pipes pass through the weather deck and are fitted with screw-down caps. Sounding pipes for engine room\ndouble-bottom tanks are fitted with counterweight self-closing cocks. It is imperative that sounding pipe caps or cocks be kept\nshut and well maintained.\nPipes passing through a dry cargo space must be inspected for physical damage after the completion of discharging\noperations. It is advisable to open and inspect air pipe headers on the exposed weather deck once every five years, following the\nfirst special survey. This is necessary because corrosion on the inside of an air pipe header will not be noticeable externally. To\nextend the life of air pipe headers, they should be galvanised.\nScrew-down caps are fitted to the top of sounding pipes. These caps should never be mislaid or replaced with wooden plugs.\nThe self-closing cocks on engine room sounding pipes should never be tied open.\n(A Master’s Guide to Ship’s Piping, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.6","internal_question_no":"06A.006","question_sort_key":6100600.119,"question_text":"If the vessel has a duct keel, is the access, mechanical ventilator, and lighting adequate and is it free of water?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":83,"source_page_end":83,"raw_source_text":"If the vessel has a duct keel, is the access, mechanical ventilator, and lighting adequate and is it\nfree of water? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.7","internal_question_no":"06A.007","question_sort_key":6100700.12,"question_text":"Is the vessel free of any apparent structural defects?","guide_to_inspection":"The inspector shall specify the structural component(s)inspected.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":83,"source_page_end":83,"raw_source_text":"Is the vessel free of any apparent structural defects? (V)\nGuide to Inspection\nThe inspector shall specify the structural component(s)inspected.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"06A","section_number":6,"section_letter":"A","section_title":"Ship’s Structure","printed_question_no":"6.8","internal_question_no":"06A.008","question_sort_key":6100800.121,"question_text":"Are cargo hold ventilation systems being maintained in good condition?","guide_to_inspection":"Every ventilator should have a positive means of closing. The closing mechanism could be in the form of a weathertight door or\na ventilator flap (or damper) set within the vent trunk and operated by an external lever, or it may consist of a cowl which can be\nscrewed down into a closed position by the operation of a valve wheel. It is essential that the closing devices are maintained and\nin a good condition, which includes being greased as needed and inspecting the gaskets to ensure an effective seal, especially in\nthe case of a fire or shipping spray in the vicinity of ventilator intakes.\nVentilation ports and fan spaces must be checked for possible loose rust or paint chips that might fall onto the cargo, causing\ncontamination. Prior to any loading operation, the fans for mechanical ventilation should be checked to ensure they are in\noperation.\nIt is recommended that the mechanical ventilators are prominently and permanently marked with the space (that is being\nserviced by the vent) and that it is indicated whether the shut-off is open or closed with the direction of the damper mechanism.\nFor various cargoes, wire mesh guards shall be fitted over the fan openings on deck. The wire mesh guards shall have a mesh\nsize not exceeding 13 x 13 mm and shall prevent foreign objects entering the fan casing which could produce sparks with the\nrotating impeller (SOLAS Regulation II-2/19.3.4.2 and MSC/Circ.1120). In addition, for the carriage of SEED CAKE UN 1386 (b),\nSEED CAKE UN 2217 and SULPHUR UN 1350, all ventilation openings on the deck shall be fitted with spark-arresting screens\n(IMSBC Code Appendix 1).\nThese screens have a much finer mesh size than wire mesh guards. A definition of the term is not included in the IMSBC Code.\nHowever, the U.S. Coast Guard (46 CFR §151.03–25), for example, defines the mesh size as follows: single screen with at least\n30 x 30 threads per square inch or two screens with 20 x 20 threads per square inch fitted in series not less than half an inch or\nmore than one and a half inches apart.\n(CARGO AND CARGO HOLD VENTILATION, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":84,"source_page_end":84,"raw_source_text":"Are cargo hold ventilation systems being maintained in good condition? (V)\nGuide to Inspection\nEvery ventilator should have a positive means of closing. The closing mechanism could be in the form of a weathertight door or\na ventilator flap (or damper) set within the vent trunk and operated by an external lever, or it may consist of a cowl which can be\nscrewed down into a closed position by the operation of a valve wheel. It is essential that the closing devices are maintained and\nin a good condition, which includes being greased as needed and inspecting the gaskets to ensure an effective seal, especially in\nthe case of a fire or shipping spray in the vicinity of ventilator intakes.\nVentilation ports and fan spaces must be checked for possible loose rust or paint chips that might fall onto the cargo, causing\ncontamination. Prior to any loading operation, the fans for mechanical ventilation should be checked to ensure they are in\noperation.\nIt is recommended that the mechanical ventilators are prominently and permanently marked with the space (that is being\nserviced by the vent) and that it is indicated whether the shut-off is open or closed with the direction of the damper mechanism.\nFor various cargoes, wire mesh guards shall be fitted over the fan openings on deck. The wire mesh guards shall have a mesh\nsize not exceeding 13 x 13 mm and shall prevent foreign objects entering the fan casing which could produce sparks with the\nrotating impeller (SOLAS Regulation II-2/19.3.4.2 and MSC/Circ.1120). In addition, for the carriage of SEED CAKE UN 1386 (b),\nSEED CAKE UN 2217 and SULPHUR UN 1350, all ventilation openings on the deck shall be fitted with spark-arresting screens\n(IMSBC Code Appendix 1).\nThese screens have a much finer mesh size than wire mesh guards. A definition of the term is not included in the IMSBC Code.\nHowever, the U.S. Coast Guard (46 CFR §151.03–25), for example, defines the mesh size as follows: single screen with at least\n30 x 30 threads per square inch or two screens with 20 x 20 threads per square inch fitted in series not less than half an inch or\nmore than one and a half inches apart.\n(CARGO AND CARGO HOLD VENTILATION, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.1","internal_question_no":"07A.001","question_sort_key":7100100.122,"question_text":"Is adequate manifold spill containment provided under the bunker manifolds, and are they clean and empty?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":85,"source_page_end":85,"raw_source_text":"Is adequate manifold spill containment provided under the bunker manifolds, and are they\nclean and empty? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.2","internal_question_no":"07A.002","question_sort_key":7100200.123,"question_text":"Are bunker transfer systems hydrostatically tested to their Maximum Allowable Working Pressure (MAWP) on an annual basis and to 1.5 times their MAWP at least twice within any five years period?","guide_to_inspection":"Bunker pipelines are defined as any pipeline used for taking on, discharging or internally transferring any fuel for consumption\non board.\nA vessel’s ‘Bunker Transfer System’ should be tested to 100% of their rated working pressure (Sometimes referred to as\nMaximum Allowable Working Pressure - MAWP) at least annually. ‘Bunker Transfer Systems’ should be tested to 1.5 times their\nrated working pressure at least twice within any five-year period.\nPipelines should be marked with the date of test and the test pressure. A vessel’s ‘Bunker Transfer System’ includes the\ndischarge pump and piping between the pump and the vessel’s manifold, excluding any non-metallic hoses. In this case the\nMAWP can be assumed to be either the pressure at which the transfer piping relief valve is set or, where no relief valve(s) are\nfitted, the maximum discharge pressure that can be developed by the vessel’s pump.\nPressure testing should be a hydrostatic test, pressure testing using compressed air is not acceptable.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":85,"source_page_end":85,"raw_source_text":"Are bunker transfer systems hydrostatically tested to their Maximum Allowable Working Pressure\n(MAWP) on an annual basis and to 1.5 times their MAWP at least twice within any five years period?\nGuide to Inspection\nBunker pipelines are defined as any pipeline used for taking on, discharging or internally transferring any fuel for consumption\non board.\nA vessel’s ‘Bunker Transfer System’ should be tested to 100% of their rated working pressure (Sometimes referred to as\nMaximum Allowable Working Pressure - MAWP) at least annually. ‘Bunker Transfer Systems’ should be tested to 1.5 times their\nrated working pressure at least twice within any five-year period.\nPipelines should be marked with the date of test and the test pressure. A vessel’s ‘Bunker Transfer System’ includes the\ndischarge pump and piping between the pump and the vessel’s manifold, excluding any non-metallic hoses. In this case the\nMAWP can be assumed to be either the pressure at which the transfer piping relief valve is set or, where no relief valve(s) are\nfitted, the maximum discharge pressure that can be developed by the vessel’s pump.\nPressure testing should be a hydrostatic test, pressure testing using compressed air is not acceptable.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.3","internal_question_no":"07A.003","question_sort_key":7100300.124,"question_text":"Are the drains, vents, pressure gauges, and thermometers on the bunker manifolds in good working order, and are blanks fitted when they are not in use?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":85,"source_page_end":85,"raw_source_text":"Are the drains, vents, pressure gauges, and thermometers on the bunker manifolds in good working order,\nand are blanks fitted when they are not in use? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.4","internal_question_no":"07A.004","question_sort_key":7100400.125,"question_text":"Are save-alls fitted around all fuel, diesel, and lubricating oil tank vents; are they clean and empty, and is the drain plug secured with a strap chain to a save-all?","guide_to_inspection":"The height of any save-alls surrounding fuel, diesel, and lubricating oil tank vents should be lower than the vent heads\nthemselves, including any extension pieces fitted to them. This precaution is necessary to prevent the ingress of water or\nthe formation of a water seal, which could obstruct the release of vacuum pressure within the tank during adverse weather\nconditions, should the save-alls become filled with water.\nThe vent heads should be clearly labelled to indicate the space that they serve. Containers should be clean, empty of water and\nfree of oil. Drain plugs should be in place in port.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":85,"source_page_end":85,"raw_source_text":"Are save-alls fitted around all fuel, diesel, and lubricating oil tank vents; are they clean and empty,\nand is the drain plug secured with a strap chain to a save-all? (V)\nGuide to Inspection\nThe height of any save-alls surrounding fuel, diesel, and lubricating oil tank vents should be lower than the vent heads\nthemselves, including any extension pieces fitted to them. This precaution is necessary to prevent the ingress of water or\nthe formation of a water seal, which could obstruct the release of vacuum pressure within the tank during adverse weather\nconditions, should the save-alls become filled with water.\nThe vent heads should be clearly labelled to indicate the space that they serve. Containers should be clean, empty of water and\nfree of oil. Drain plugs should be in place in port.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.5","internal_question_no":"07A.005","question_sort_key":7100500.126,"question_text":"Are there procedures for the analysis of fuel, lubricating and hydraulic oils, and are oil sampling requirements aligned with equipment manufacturer’s recommendations?","guide_to_inspection":"The inspector shall review the test results and recommendations from the last analysis/report. A Finding should be recorded\nonly if the status of the analysis report is marked as “Critical” and no objective evidence is available to confirm that corrective\nactions have been taken. Record in comments any actions that have been taken if the status of the analysis report was marked\n“Critical.”\nRecord a Finding when the instructions from the engine manufacturer as to how often oil samples should be drawn for testing\nwas not followed.\nRightShip recommends that the vessel’s manager subscribe to a fuel bunker analysis and advisory service.\nFuel oil means any fuel delivered to and intended for combustion purposes for propulsion or operation on board a ship, including\ngas, distillate, and residual fuel.\n(Regulation 2.1.14 of MARPOL Annex VI)\nLubricating oil analysis by approved organisations is an important tool for monitoring the condition of machinery and\ncomponents. It is highly recommended that laboratory analysis programmes for lubricating oil and hydraulic oil are\nimplemented on board and are closely monitored by the shore-based technical management.\nThe instructions and procedures for the analysis of fuel shall be incorporated in the safety management system.\nIn the absence of clear instructions from the engine manufacturer as to how often oil samples should be drawn for testing, the\nlubricant manufacturer should be contacted for advice.\nAppendix V of MARPOL Annex VI details the information that should be displayed on the Bunker Delivery Note (BDN). From 1st\nMay 2024, the BDN should state a specific flashpoint value of the fuel if the flashpoint is below 70°C. Otherwise, it should include\na statement that the flashpoint has been measured at or above 70°C. The BDN should also stipulate the relevant test method\nfor the flashpoint, which is ISO 2719:2016, ‘Determination of Flashpoint – Pensky-Martens Closed Cup Method.’ This could be\neither Procedure A (for distillate fuels) or Procedure B (for residual fuels).","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":85,"source_page_end":86,"raw_source_text":"Are there procedures for the analysis of fuel, lubricating and hydraulic oils, and are oil sampling requirements\naligned with equipment manufacturer’s recommendations? (V & M)\nGuide to Inspection\nThe inspector shall review the test results and recommendations from the last analysis/report. A Finding should be recorded\nonly if the status of the analysis report is marked as “Critical” and no objective evidence is available to confirm that corrective\nactions have been taken. Record in comments any actions that have been taken if the status of the analysis report was marked\n“Critical.”\nRecord a Finding when the instructions from the engine manufacturer as to how often oil samples should be drawn for testing\nwas not followed.\nRightShip recommends that the vessel’s manager subscribe to a fuel bunker analysis and advisory service.\nFuel oil means any fuel delivered to and intended for combustion purposes for propulsion or operation on board a ship, including\ngas, distillate, and residual fuel.\n(Regulation 2.1.14 of MARPOL Annex VI)\nLubricating oil analysis by approved organisations is an important tool for monitoring the condition of machinery and\ncomponents. It is highly recommended that laboratory analysis programmes for lubricating oil and hydraulic oil are\nimplemented on board and are closely monitored by the shore-based technical management.\nThe instructions and procedures for the analysis of fuel shall be incorporated in the safety management system.\nIn the absence of clear instructions from the engine manufacturer as to how often oil samples should be drawn for testing, the\nlubricant manufacturer should be contacted for advice.\nAppendix V of MARPOL Annex VI details the information that should be displayed on the Bunker Delivery Note (BDN). From 1st\nMay 2024, the BDN should state a specific flashpoint value of the fuel if the flashpoint is below 70°C. Otherwise, it should include\na statement that the flashpoint has been measured at or above 70°C. The BDN should also stipulate the relevant test method\nfor the flashpoint, which is ISO 2719:2016, ‘Determination of Flashpoint – Pensky-Martens Closed Cup Method.’ This could be\neither Procedure A (for distillate fuels) or Procedure B (for residual fuels).","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.6","internal_question_no":"07A.006","question_sort_key":7100600.127,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":86,"source_page_end":86,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.7","internal_question_no":"07A.007","question_sort_key":7100700.128,"question_text":"Are bunkering and oil fuel transfer procedures carefully planned and executed in accordance with industry standards, are the details of the last operation in accordance with industry standards, is the vessel equipped with a procedure for sampling the oil fuel used on board, and are bunker samples stored in a sheltered location?","guide_to_inspection":"Planning of bunkering operations should include the following:\n> Deck scuppers must be securely plugged during all bunkering operations to prevent the accidental discharge of fuel into the sea.\n> An accurate summary of the different quantities and grades of fuel to be supplied.\n> A plan of which bunker tanks are to be filled, which must include the type and quantity assigned to each tank and the maximum\nfilling volumes.\n> A schematic diagram of the bunker system and proper valve line-up.\n> The filling sequence and the required pumping rate, including initial, maximum, and topping off rate.\n> An indication of the safety margin or “slack” space to be left in each tank. For example, no tank is to be more than 90% full.\n> Soundings of each tank prior to commencement of bunkering and the expected soundings/ullages on completion.\n> The method of sounding and/or ullaging, which can be stipulated to avoid confusion.\n> Details of who is in overall charge of the operation; this is usually the Chief Engineer, and the plan should also indicate who else is\ninvolved and their respective duties.\n> Emergency procedures and contacts\n> Procedure of line draining and blowing after completion of bunkering\n> If a common line is used for multiple grades, then the line flushing volumes and procedures\n> Testing of high-level alarms setting in the fuel oil tanks or a substitute means in case alarms are not provided.\n> Proper identification and markings of the valves on the bunker lines.\n> Procedure for changing over tanks during the bunkering\n> Vessel stability drafts, trim, and list during the various stages of bunkering\n> Manning requirements to execute the operation safely.\n(Safe Bunkering Practices, 2013)\nThe procedure should specify the locations of fuel oil sampling points and the sampling procedures to be used to confirm the fuel oil’s\nSulphur level.\n> The MARPOL sample of the bunker fuel delivered to the ship during the bunkering operation must be taken in accordance with\nMSC-MEPC.2/Circ.18,\n> Commercial samples’ taken during bunker operation for the purpose of verifying physical and chemical properties should be in\naccordance with ISO 8217;\n> For an in-use sample of a ship’s fuel oil (MEPC.1/Circ.864/Rev.1)\n> A sample of the fuel oil to be used or carried in tanks for usage on board (MEPC.1/Circ.889)\nIt is critical to distinguish between a MARPOL sample and one obtained commercially. The sampling location of the MARPOL sample\nis regulated, whereas for the commercial sample it is not. As a result, the location of commercial samples is left to the parties.\nThe retained sample should be stored in a sheltered location where it will not be subject to elevated temperatures, preferably at a cool/\nambient temperature, and where it will not be exposed to direct sunlight.\nPursuant to regulation 18(6) of Annex VI of MARPOL 73/78, the retained sample should be retained under the ship’s control until the\nfuel oil is substantially consumed, but in any case, for a period of not less than 12 months from the time of delivery.\n(2009 Guidelines for the Sampling of Fuel Oil for Determination of Compliance with the Revised Marpol Annex VI,2009)\nRightship urges the vessel’s manager to establish a procedure for bunker sampling management, including the safe disposal of the\nsample when no longer required. Consideration should be given to storing samples in a location protected by a localised fixed fire\nfighting system, such as the paint store.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":86,"source_page_end":86,"raw_source_text":"Are bunkering and oil fuel transfer procedures carefully planned and executed in accordance with industry\nstandards, are the details of the last operation in accordance with industry standards, is the vessel equipped\nwith a procedure for sampling the oil fuel used on board, and are bunker samples stored in a sheltered location? (V)\nGuide to Inspection\nPlanning of bunkering operations should include the following:\n> Deck scuppers must be securely plugged during all bunkering operations to prevent the accidental discharge of fuel into the sea.\n> An accurate summary of the different quantities and grades of fuel to be supplied.\n> A plan of which bunker tanks are to be filled, which must include the type and quantity assigned to each tank and the maximum\nfilling volumes.\n> A schematic diagram of the bunker system and proper valve line-up.\n> The filling sequence and the required pumping rate, including initial, maximum, and topping off rate.\n> An indication of the safety margin or “slack” space to be left in each tank. For example, no tank is to be more than 90% full.\n> Soundings of each tank prior to commencement of bunkering and the expected soundings/ullages on completion.\n> The method of sounding and/or ullaging, which can be stipulated to avoid confusion.\n> Details of who is in overall charge of the operation; this is usually the Chief Engineer, and the plan should also indicate who else is\ninvolved and their respective duties.\n> Emergency procedures and contacts\n> Procedure of line draining and blowing after completion of bunkering\n> If a common line is used for multiple grades, then the line flushing volumes and procedures\n> Testing of high-level alarms setting in the fuel oil tanks or a substitute means in case alarms are not provided.\n> Proper identification and markings of the valves on the bunker lines.\n> Procedure for changing over tanks during the bunkering\n> Vessel stability drafts, trim, and list during the various stages of bunkering\n> Manning requirements to execute the operation safely.\n(Safe Bunkering Practices, 2013)\nThe procedure should specify the locations of fuel oil sampling points and the sampling procedures to be used to confirm the fuel oil’s\nSulphur level.\n> The MARPOL sample of the bunker fuel delivered to the ship during the bunkering operation must be taken in accordance with\nMSC-MEPC.2/Circ.18,\n> Commercial samples’ taken during bunker operation for the purpose of verifying physical and chemical properties should be in\naccordance with ISO 8217;\n> For an in-use sample of a ship’s fuel oil (MEPC.1/Circ.864/Rev.1)\n> A sample of the fuel oil to be used or carried in tanks for usage on board (MEPC.1/Circ.889)\nIt is critical to distinguish between a MARPOL sample and one obtained commercially. The sampling location of the MARPOL sample\nis regulated, whereas for the commercial sample it is not. As a result, the location of commercial samples is left to the parties.\nThe retained sample should be stored in a sheltered location where it will not be subject to elevated temperatures, preferably at a cool/\nambient temperature, and where it will not be exposed to direct sunlight.\nPursuant to regulation 18(6) of Annex VI of MARPOL 73/78, the retained sample should be retained under the ship’s control until the\nfuel oil is substantially consumed, but in any case, for a period of not less than 12 months from the time of delivery.\n(2009 Guidelines for the Sampling of Fuel Oil for Determination of Compliance with the Revised Marpol Annex VI,2009)\nRightship urges the vessel’s manager to establish a procedure for bunker sampling management, including the safe disposal of the\nsample when no longer required. Consideration should be given to storing samples in a location protected by a localised fixed fire\nfighting system, such as the paint store.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.8","internal_question_no":"07A.008","question_sort_key":7100800.129,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":87,"source_page_end":87,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.9","internal_question_no":"07A.009","question_sort_key":7100900.13,"question_text":"Are ship-specific procedures to control the change from residual to low-sulphur / distillate fuels and vice versa provided, and is the fuel oil change over logbook and data collection system being maintained correctly?","guide_to_inspection":"The use of a fuel change over calculator is recommended.\nSwitching from one type of fuel to another is an operation that does have risks. Vessels trading between areas with different\nsulphur limitations are required to have specific and detailed change-over procedures. The crew needs to be well trained and\naware of any risks associated with the change-over – otherwise they risk engine failure, power loss or even blackout. A full risk\nassessment should be conducted by all involved in the procedure.\n(Emission Control Areas – Ultra Low Sulphur Fuel Oil Change-over Procedures, 2014)\nAccording to MARPOL Annex VI, vessels that use both high and low sulphur fuel oils should have a written change-over\nprocedure. The method should detail how the change-over will be carried out, as well as the time required to flush high sulphur\nfuel out of the system following the changeover of service tanks, as well as the number of hours required before entering the\nECA to begin the change-over.\nBefore entering an ECA, the ship should switch from high sulphur fuel to low sulphur fuel with a sulphur content of less than 0.10\npercent by mass. This operation begins by shutting down consumption from the high sulphur service tank using the three-way\nvalve and replacing it with fuel from the low sulphur service tank. Throughout the changeover procedure, the low sulphur fuel will\ncontinually dilute the fuel in the service system. The time required to reach the 0.10 percent sulphur level varies according to the\namount of machinery fuel oil consumed, the volume of the service system, and the sulphur content of the fuel.\nThroughout the changeover procedure, all steps must be recorded in the engine logbook and Marine sulphur record book. All\nentries must accurately reflect the quantities, the time of changeover, and the ship’s position. Additionally, what time did the ship\nenter and exit the ECA/SECA should be documented along with the vessel’s position. When the changeover process is complete\nand the vessel is operating on low sulphur fuel oil, the Chief Engineer shall notify the Master.\n(Fuel change-over procedure, 2022)\nFrom 01 May 2025, amendments to MARPOL Annex VI Regulation 14.3.5, as amended by IMO Resolution MEPC.361(79),\nprohibited ships operating within the Mediterranean Sea ECA from using fuel oils with a sulphur content exceeding 0.10% m/m\nunless an approved equivalent arrangement is used such as Exhaust Gas Cleaning Systems.\nFrom 01 March 2026, in accordance with MARPOL Annex VI Regulations 13, as amended by IMO Resolution MEPC.392(82),\nships operating in either the Canadian Arctic ECA or Norwegian Sea ECA with a marine diesel engine with power output of more\nthan 130kW are required to be certified to the NOx Technical Code 2008 to meet the NOx Tier III standard, as follows:\nFor the Canadian Arctic ECA, ships with keels laid or at a similar stage of construction on or after 1 January 2025.\nFor the Norwegian Sea ECA:\n> Ships with a building contract placed on or after 1 March 2026\n> In absence of a building contract, ships with keels laid or at a similar stage of construction on or after 1 September 2026; or\n> The delivery is on or after 1 March 2030.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":87,"source_page_end":87,"raw_source_text":"Are ship-specific procedures to control the change from residual to low-sulphur / distillate fuels\nand vice versa provided, and is the fuel oil change over logbook and data collection system being\nmaintained correctly? (V & M)\nGuide to Inspection\nThe use of a fuel change over calculator is recommended.\nSwitching from one type of fuel to another is an operation that does have risks. Vessels trading between areas with different\nsulphur limitations are required to have specific and detailed change-over procedures. The crew needs to be well trained and\naware of any risks associated with the change-over – otherwise they risk engine failure, power loss or even blackout. A full risk\nassessment should be conducted by all involved in the procedure.\n(Emission Control Areas – Ultra Low Sulphur Fuel Oil Change-over Procedures, 2014)\nAccording to MARPOL Annex VI, vessels that use both high and low sulphur fuel oils should have a written change-over\nprocedure. The method should detail how the change-over will be carried out, as well as the time required to flush high sulphur\nfuel out of the system following the changeover of service tanks, as well as the number of hours required before entering the\nECA to begin the change-over.\nBefore entering an ECA, the ship should switch from high sulphur fuel to low sulphur fuel with a sulphur content of less than 0.10\npercent by mass. This operation begins by shutting down consumption from the high sulphur service tank using the three-way\nvalve and replacing it with fuel from the low sulphur service tank. Throughout the changeover procedure, the low sulphur fuel will\ncontinually dilute the fuel in the service system. The time required to reach the 0.10 percent sulphur level varies according to the\namount of machinery fuel oil consumed, the volume of the service system, and the sulphur content of the fuel.\nThroughout the changeover procedure, all steps must be recorded in the engine logbook and Marine sulphur record book. All\nentries must accurately reflect the quantities, the time of changeover, and the ship’s position. Additionally, what time did the ship\nenter and exit the ECA/SECA should be documented along with the vessel’s position. When the changeover process is complete\nand the vessel is operating on low sulphur fuel oil, the Chief Engineer shall notify the Master.\n(Fuel change-over procedure, 2022)\nFrom 01 May 2025, amendments to MARPOL Annex VI Regulation 14.3.5, as amended by IMO Resolution MEPC.361(79),\nprohibited ships operating within the Mediterranean Sea ECA from using fuel oils with a sulphur content exceeding 0.10% m/m\nunless an approved equivalent arrangement is used such as Exhaust Gas Cleaning Systems.\nFrom 01 March 2026, in accordance with MARPOL Annex VI Regulations 13, as amended by IMO Resolution MEPC.392(82),\nships operating in either the Canadian Arctic ECA or Norwegian Sea ECA with a marine diesel engine with power output of more\nthan 130kW are required to be certified to the NOx Technical Code 2008 to meet the NOx Tier III standard, as follows:\nFor the Canadian Arctic ECA, ships with keels laid or at a similar stage of construction on or after 1 January 2025.\nFor the Norwegian Sea ECA:\n> Ships with a building contract placed on or after 1 March 2026\n> In absence of a building contract, ships with keels laid or at a similar stage of construction on or after 1 September 2026; or\n> The delivery is on or after 1 March 2030.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.10","internal_question_no":"07A.010","question_sort_key":7101000.131,"question_text":"Are the Quick Closing Valves serving fuel and lubricating oil systems being regularly tested and in good order?","guide_to_inspection":"Quick Closing Valves are fitted to the outlets of lubricating and fuel oil storage, and settling and service tanks within the\nmachinery space, boiler room and the emergency generator room. These spring-loaded valves may be operated locally or\nremotely by pull wires, hydraulics, or compressed air. Quick Closing Valves are essential safety devices. They should be properly\nmaintained.\n(Quick Closing and Self Closing Valves, 2011)\nIn multi-engine installations which are supplied from the same fuel source, means of isolating the fuel supply and spill piping\nto individual engines, shall be provided. The means of isolation shall not affect the operation of the other engines and shall be\noperable from a position not rendered inaccessible by a fire on any of the engines. ( SOLAS 74 2020)\nAMSA Marine Notice 2024/05, “Fuel Isolation for Multi-Engine Installations,” states that one common solution is to install a\nquick-closing valve on the fuel supply line to the engine, between the fuel changeover valves and the engine, with a remote\nactuator in another part of the machinery space.\nFor ships built after June 2009, where possible, the valves or the actuator for the remote closing valves should be at least 5\nmetres from the engine in any direction. Where this is not possible, protection by obstructions may be implemented.\nFor further inspection references, please refer to AMSA Marine Notice 2024/05 and pages 24, 25, 26, and 27 of MSC.1/Circ.1321,\ndated 11 June 2009.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":87,"source_page_end":87,"raw_source_text":"Are the Quick Closing Valves serving fuel and lubricating oil systems being regularly tested and in good order? (V)\nGuide to Inspection\nQuick Closing Valves are fitted to the outlets of lubricating and fuel oil storage, and settling and service tanks within the\nmachinery space, boiler room and the emergency generator room. These spring-loaded valves may be operated locally or\nremotely by pull wires, hydraulics, or compressed air. Quick Closing Valves are essential safety devices. They should be properly\nmaintained.\n(Quick Closing and Self Closing Valves, 2011)\nIn multi-engine installations which are supplied from the same fuel source, means of isolating the fuel supply and spill piping\nto individual engines, shall be provided. The means of isolation shall not affect the operation of the other engines and shall be\noperable from a position not rendered inaccessible by a fire on any of the engines. ( SOLAS 74 2020)\nAMSA Marine Notice 2024/05, “Fuel Isolation for Multi-Engine Installations,” states that one common solution is to install a\nquick-closing valve on the fuel supply line to the engine, between the fuel changeover valves and the engine, with a remote\nactuator in another part of the machinery space.\nFor ships built after June 2009, where possible, the valves or the actuator for the remote closing valves should be at least 5\nmetres from the engine in any direction. Where this is not possible, protection by obstructions may be implemented.\nFor further inspection references, please refer to AMSA Marine Notice 2024/05 and pages 24, 25, 26, and 27 of MSC.1/Circ.1321,\ndated 11 June 2009.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.11","internal_question_no":"07A.011","question_sort_key":7101100.132,"question_text":"Are high pressure fuel delivery pipes of diesel engines protected with a jacketed piping and alarm system, and is the alarm system being tested regularly and in good order?","guide_to_inspection":"External high pressure fuel delivery lines between the high-pressure fuel pumps and fuel injectors shall be protected with a\njacketed piping system capable of containing fuel from a high-pressure line failure. A jacketed pipe incorporates an outer pipe\ninto which the high-pressure fuel pipe is placed, forming a permanent assembly. The jacketed piping system shall include a\nmeans for the collection of leakages and arrangements shall be provided for an alarm to be given of a fuel line failure.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":88,"source_page_end":88,"raw_source_text":"Are high pressure fuel delivery pipes of diesel engines protected with a jacketed piping and alarm system,\nand is the alarm system being tested regularly and in good order? (V)\nGuide to Inspection\nExternal high pressure fuel delivery lines between the high-pressure fuel pumps and fuel injectors shall be protected with a\njacketed piping system capable of containing fuel from a high-pressure line failure. A jacketed pipe incorporates an outer pipe\ninto which the high-pressure fuel pipe is placed, forming a permanent assembly. The jacketed piping system shall include a\nmeans for the collection of leakages and arrangements shall be provided for an alarm to be given of a fuel line failure.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.12","internal_question_no":"07A.012","question_sort_key":7101200.133,"question_text":"Are purifier rooms and fuel and lubricating oil handling areas ventilated, free of oil leaks and clean?","guide_to_inspection":"","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"not_provided","source_page_start":88,"source_page_end":88,"raw_source_text":"Are purifier rooms and fuel and lubricating oil handling areas ventilated, free of oil leaks and clean? (V)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07A","section_number":7,"section_letter":"A","section_title":"Fuel Management (Oil Fuel)","printed_question_no":"7.13","internal_question_no":"07A.013","question_sort_key":7101300.134,"question_text":"Is the reserve fuel tank of the emergency generator filled with sufficient fuel of a suitable type for at least 18 hours operation?","guide_to_inspection":"If the vessel is trading in area with sub-zero temperature, the fuel tank of the emergency generator should be charged with fuel\ndesigned for use in sub-zero temperatures.\n> The generator should be capable of providing full load requirements for at least 18 hours.\n> Every oil fuel pipe (which, if damaged, would allow oil to escape from a storage, settling or daily service tank situated above\nthe double bottom) shall be fitted with a cock or valve directly on the tank capable of being closed from a safe position,\noutside the space concerned, in the event of a fire occurring in the space in which such tanks are situated.\n> Oil fuel pipes (which, if damaged, would allow oil to escape from a storage, settling or daily service tank having a capacity\nof 500 litres and above situated above the double bottom) shall be fitted with a cock or valve directly on the tank capable of\nbeing closed from a safe position, outside the space concerned, in the event of a fire occurring in the space in which such\nthe tanks are situated.\n> The controls for the remote operation of the valve for the emergency generator fuel tank shall be in a separate location\nfrom the controls for the remote operation of other valves for tanks located in machinery spaces.\n(SOLAS 74, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":88,"source_page_end":88,"raw_source_text":"Is the reserve fuel tank of the emergency generator filled with sufficient fuel of a suitable type for at\nleast 18 hours operation? (V)\nGuide to Inspection\nIf the vessel is trading in area with sub-zero temperature, the fuel tank of the emergency generator should be charged with fuel\ndesigned for use in sub-zero temperatures.\n> The generator should be capable of providing full load requirements for at least 18 hours.\n> Every oil fuel pipe (which, if damaged, would allow oil to escape from a storage, settling or daily service tank situated above\nthe double bottom) shall be fitted with a cock or valve directly on the tank capable of being closed from a safe position,\noutside the space concerned, in the event of a fire occurring in the space in which such tanks are situated.\n> Oil fuel pipes (which, if damaged, would allow oil to escape from a storage, settling or daily service tank having a capacity\nof 500 litres and above situated above the double bottom) shall be fitted with a cock or valve directly on the tank capable of\nbeing closed from a safe position, outside the space concerned, in the event of a fire occurring in the space in which such\nthe tanks are situated.\n> The controls for the remote operation of the valve for the emergency generator fuel tank shall be in a separate location\nfrom the controls for the remote operation of other valves for tanks located in machinery spaces.\n(SOLAS 74, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.1","internal_question_no":"07B.001","question_sort_key":7200100.135,"question_text":"Is there an approved LNG Fuel Handing and Emergency Procedure Manual, and are crew familiar with the bunkering and emergency procedures such as leakage, fire or potential fuel stratification resulting in rollover?","guide_to_inspection":"LNG bunker operations shall be conducted in accordance with the detailed fuel handling manual and the emergency procedures\nspecified in 18.2.3 of the IGF Code that have been approved for the vessel or vessels by their flag State, recognized organization\nor classification society that has classed the vessel and complies with the applicable uniform interpretations and requirements\nposted by the IACS.\nTransfers from terminals or mobile facilities shall be conducted in accordance with approved terminal or mobile facility transfer\nprocedures.\nThe LNG Fuel Handing and Emergency Procedure Manual requires a level of staffing during bunkering operations; however, it\ndoes not relieve vessel captains or facility operators from their responsibilities.\n(ISO 20519:2017, 2017)\nA low flashpoint bunkering manual should be established with involved parties agreeing technically and commercially on\nmethodology, flow rate, temperature, pressure of the delivery of low flashpoint fuels and receiving tanks. This manual shall\ngather all the information, certificates, procedures, and checklist(s) necessary for an effective and safe low flashpoint bunkering\noperation.\nThe documented operational procedures shall cover the loading, storage, operation, maintenance and inspection of systems\nand emergency procedures.\n“Guidelines for Gas Fuelled Ships” and “Guidelines for Ships Using Low Flashpoint Fuels” from ClassNK provides further\nguidance on how to prepare such a manual.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":89,"source_page_end":89,"raw_source_text":"Is there an approved LNG Fuel Handing and Emergency Procedure Manual, and are crew familiar with the\nbunkering and emergency procedures such as leakage, fire or potential fuel stratification resulting in rollover? (V)\nGuide to Inspection\nLNG bunker operations shall be conducted in accordance with the detailed fuel handling manual and the emergency procedures\nspecified in 18.2.3 of the IGF Code that have been approved for the vessel or vessels by their flag State, recognized organization\nor classification society that has classed the vessel and complies with the applicable uniform interpretations and requirements\nposted by the IACS.\nTransfers from terminals or mobile facilities shall be conducted in accordance with approved terminal or mobile facility transfer\nprocedures.\nThe LNG Fuel Handing and Emergency Procedure Manual requires a level of staffing during bunkering operations; however, it\ndoes not relieve vessel captains or facility operators from their responsibilities.\n(ISO 20519:2017, 2017)\nA low flashpoint bunkering manual should be established with involved parties agreeing technically and commercially on\nmethodology, flow rate, temperature, pressure of the delivery of low flashpoint fuels and receiving tanks. This manual shall\ngather all the information, certificates, procedures, and checklist(s) necessary for an effective and safe low flashpoint bunkering\noperation.\nThe documented operational procedures shall cover the loading, storage, operation, maintenance and inspection of systems\nand emergency procedures.\n“Guidelines for Gas Fuelled Ships” and “Guidelines for Ships Using Low Flashpoint Fuels” from ClassNK provides further\nguidance on how to prepare such a manual.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.2","internal_question_no":"07B.002","question_sort_key":7200200.136,"question_text":"Do the Master, engineering officers and all personnel with immediate responsibility for the care and use of fuels and fuel systems on ship, hold a certificate in advanced training for service on the ships subject to the IGF Code?","guide_to_inspection":"Masters, engineering officers and all personnel with immediate responsibility for the care and use of fuels and fuel systems on\nships subject to the IGF Code shall hold a certificate in advanced training for service on ships subject to the IGF Code.\nEvery candidate for certification in advanced training for service on ships subject to the IGF Code shall:\n1. Have successfully completed the approved advanced training required by regulation V/3, paragraph 7 in accordance with their\ncapacity, duties and responsibilities as set out in STCW Code table A-V/3-2; and\n2. Provide evidence that the required standard of competence has been achieved in accordance with the methods and the\ncriteria for evaluating competence tabulated in columns 3 and 4 of STCW Code table A-V/3-2; or\n3. Have received appropriate training and certification according to the requirements for service on liquefied gas tankers as set\nout in STCW Code regulation V/3, paragraph 8.\nSeafarers holding the advanced training for service on ships subject to the IGF Code shall, at intervals not exceeding five\nyears, undertake appropriate refresher training or be required to provide evidence of having achieved the required standard of\ncompetence within the previous five years.\n(Regulation V3, STCW 2010)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":89,"source_page_end":89,"raw_source_text":"Do the Master, engineering officers and all personnel with immediate responsibility for the care and\nuse of fuels and fuel systems on ship, hold a certificate in advanced training for service on the ships\nsubject to the IGF Code? (V)\nGuide to Inspection\nMasters, engineering officers and all personnel with immediate responsibility for the care and use of fuels and fuel systems on\nships subject to the IGF Code shall hold a certificate in advanced training for service on ships subject to the IGF Code.\nEvery candidate for certification in advanced training for service on ships subject to the IGF Code shall:\n1. Have successfully completed the approved advanced training required by regulation V/3, paragraph 7 in accordance with their\ncapacity, duties and responsibilities as set out in STCW Code table A-V/3-2; and\n2. Provide evidence that the required standard of competence has been achieved in accordance with the methods and the\ncriteria for evaluating competence tabulated in columns 3 and 4 of STCW Code table A-V/3-2; or\n3. Have received appropriate training and certification according to the requirements for service on liquefied gas tankers as set\nout in STCW Code regulation V/3, paragraph 8.\nSeafarers holding the advanced training for service on ships subject to the IGF Code shall, at intervals not exceeding five\nyears, undertake appropriate refresher training or be required to provide evidence of having achieved the required standard of\ncompetence within the previous five years.\n(Regulation V3, STCW 2010)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.3","internal_question_no":"07B.003","question_sort_key":7200300.137,"question_text":"Do seafarers responsible for designated safety duties associated with the care, use or emergency response to the fuel onboard the ship, hold a certificate in basic training for service on ships subject to the IGF Code?","guide_to_inspection":"Every candidate for certification in basic training for service on ships subject to the IGF Code shall:\n1. Have successfully completed the approved basic training required by regulation V/3, paragraph 5, in accordance with their\ncapacity, duties and responsibilities as set out in STCW Code table A-V/3-1; and\n2. Be required to provide evidence that the required standard of competence has been achieved in accordance with the methods\nand the criteria for evaluating competence tabulated in columns 3 and 4 of STCW Code table A-V/3-1.\nSeafarers holding the basic training for service on ships subject to the IGF Code shall, at intervals not exceeding five years,\nundertake appropriate refresher training or be required to provide evidence of having achieved the required standard of\ncompetence within the previous five years.\n(Regulation V3, STCW 2010)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":89,"source_page_end":89,"raw_source_text":"Do seafarers responsible for designated safety duties associated with the care, use or emergency response\nto the fuel onboard the ship, hold a certificate in basic training for service on ships subject to the IGF Code? (V)\nGuide to Inspection\nEvery candidate for certification in basic training for service on ships subject to the IGF Code shall:\n1. Have successfully completed the approved basic training required by regulation V/3, paragraph 5, in accordance with their\ncapacity, duties and responsibilities as set out in STCW Code table A-V/3-1; and\n2. Be required to provide evidence that the required standard of competence has been achieved in accordance with the methods\nand the criteria for evaluating competence tabulated in columns 3 and 4 of STCW Code table A-V/3-1.\nSeafarers holding the basic training for service on ships subject to the IGF Code shall, at intervals not exceeding five years,\nundertake appropriate refresher training or be required to provide evidence of having achieved the required standard of\ncompetence within the previous five years.\n(Regulation V3, STCW 2010)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"07B","section_number":7,"section_letter":"B","section_title":"Fuel Management (Alternative Fuel- LNG)","printed_question_no":"7.4","internal_question_no":"07B.004","question_sort_key":7200400.138,"question_text":"Does the schedule of drills and exercises related to LNG fuels address potential emergency shipboard situations and has it been conducted effectively?","guide_to_inspection":"Exercises related to low-flashpoint fuels should include at least the following:\n> A desktop exercises.\n> Review of fuelling procedures based on the ISM approved Company Operations Procedures Manual.\n> Responses to identified hazardous contingences.\n> •Tests of equipment intended for contingency response.\n> Reviews to confirm that assigned seafarers are trained to perform assigned duties during fuelling and contingency\nresponses.\nGas related exercises may be incorporated into periodical drills required by SOLAS. The response and safety system for hazards\nand accident control shall be reviewed and tested.\n(RESOLUTION MSC.391(95), ADOPTION OF THE INTERNATIONAL CODE OF SAFETY FOR SHIPS USING\nGASES OR OTHER LOW-FLASHPOINT FUELS (IGF CODE), 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":90,"source_page_end":90,"raw_source_text":"Does the schedule of drills and exercises related to LNG fuels address potential emergency\nshipboard situations and has it been conducted effectively? (V)\nGuide to Inspection\nExercises related to low-flashpoint fuels should include at least the following:\n> A desktop exercises.\n> Review of fuelling procedures based on the ISM approved Company Operations Procedures Manual.\n> Responses to identified hazardous contingences.\n> •Tests of equipment intended for contingency response.\n> Reviews to confirm that assigned seafarers are trained to perform assigned duties during fuelling and contingency\nresponses.\nGas related exercises may be incorporated into periodical drills required by SOLAS. The response and safety system for hazards\nand accident control shall be reviewed and tested.\n(RESOLUTION MSC.391(95), ADOPTION OF THE INTERNATIONAL CODE OF SAFETY FOR SHIPS USING\nGASES OR OTHER LOW-FLASHPOINT FUELS (IGF CODE), 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ51$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 5/15 imported.' AS result,
  '05A.015' AS chunk_first_question,
  '07B.004' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
